def average_values(dicts):
    averages = {}
    counts = {}
    for d in dicts:
        for key, value in d.items():
            if key in averages:
                averages[key] += value
                counts[key] += 1
            else:
                averages[key] = value
                counts[key] = 1
    for key in averages:
        averages[key] /= counts[key]
    return averages

