def merge_dicts_with_lists(dicts):
    merged = {}
    for d in dicts:
        for key, value in d.items():
            if key in merged:
                merged[key].update(value)
            else:
                merged[key] = set(value)
    for key in merged:
        merged[key] = list(merged[key])
    return merged

