def is_anagram(string1, string2):
    string1 = string1.replace(' ', '').lower()
    string2 = string2.replace(' ', '').lower()
    if len(string1) != len(string2):
        return False
    char_count1 = {}
    char_count2 = {}
    for char in string1:
        if char in char_count1:
            char_count1[char] += 1
        else:
            char_count1[char] = 1
    for char in string2:
        if char in char_count2:
            char_count2[char] += 1
        else:
            char_count2[char] = 1
    return char_count1 == char_count2

